import TomSelect from"../../tom-select.js";function getDom(t){if(t.jquery)return t[0];if(t instanceof HTMLElement)return t;if(-1<t.indexOf("<")){let e=document.createElement("div");return e.innerHTML=t.trim(),e.firstChild}return document.querySelector(t)}TomSelect.define("clear_button",function(t){var r=this;t=Object.assign({className:"clear-button",title:"Clear All",html:e=>`<div class="${e.className}" title="${e.title}">&times;</div>`},t),r.hook("after","setup",()=>{var e=getDom(t.html(t));e.addEventListener("click",e=>{r.clear(),e.preventDefault(),e.stopPropagation()}),r.control.appendChild(e)})});